const club = $('Get Club').first().json;
const url = (club.website_url || '').trim();
const isLive = (c) => (c >= 200 && c < 400) || c === 401 || c === 403 || c === 429; // exists (maybe bot-blocked)
let live = false;
if (url) {
  try {
    const res = await this.helpers.httpRequest({ method:'GET', url, timeout:8000, returnFullResponse:true, ignoreHttpStatusErrors:true, followRedirect:true, headers:{'User-Agent':'Mozilla/5.0 (compatible; leblovina)'} });
    live = isLive(res.statusCode || 0);
  } catch(e) { live = false; }   // DNS fail / timeout / refused -> dead
}
const stop = new Set(['volley','volleyball','voley','voleibol','pallavolo','club','clube','klub','kluby','asd','ssd','polisportiva','associazione','association','sportiva','sport','sports','team','siatkowki','siatkowka','the','de','di','del','la','el','of','and','vc','cv','vbc','vk']);
const tokens = String(club.name||'').toLowerCase().normalize('NFD').replace(/\p{M}/gu,'').replace(/[^\p{L}\p{N}\s]/gu,' ').split(/\s+/).filter(t => t.length>=3 && !stop.has(t));
const q = [club.name, club.city, club.country, 'volleyball'].filter(Boolean).join(' ');
const q2 = [club.name, club.city, club.country].filter(Boolean).join(' ');   // D: broader requery (no sport term) -> fallback pool only
const src = String(club.website_source||'');
const force = !!(($('Webhook').first().json.body)||{}).force;   // 'resolve all' re-resolves auto/empty-sourced clubs even if currently live
const recheck = !!(($('Webhook').first().json.body)||{}).recheck;   // re-harvest + belongs-check an existing live URL without re-spending Serper
const protectedSrc = (src==='official_list' || src==='manual');
const needsResolve = (force && !protectedSrc) ? true : !live;
return [{ json: { clubId: club.id, name: club.name, city: club.city, country: club.country, currentUrl: url, currentSource: src, live, needsResolve, recheck, nameTokens: tokens, query: q, query2: q2 } }];

const v = $('Validate').first().json;
const club = $('Get Club').first().json;
const clubId = v.clubId;
const curSource = String(v.currentSource||'');
const isLive = (c) => (c >= 200 && c < 400) || c === 401 || c === 403 || c === 429;
const hostOf = (u) => String(u||'').replace(/^https?:\/\//i,'').replace(/^www\./i,'').split(/[\/?#]/)[0].toLowerCase();
const pathOf = (u) => { const s = String(u||'').replace(/^https?:\/\//i,''); const i = s.search(/[\/?#]/); if (i < 0) return ''; return s.slice(i).split(/[?#]/)[0]; };
const blocked = /(facebook|instagram|twitter|x\.com|linkedin|youtube|tiktok|wikipedia|volleybox|sofascore|flashscore|transfermarkt|eurosport|maps\.google|google\.|tripadvisor|yelp|amazon|ticketmaster|eventim|ticketportal|ticketpro|spordiregister|rejstrik|\.gov)/i;
const UA = { 'User-Agent':'Mozilla/5.0 (compatible; leblovina)' };
const get = async (u) => { try { const r = await this.helpers.httpRequest({ method:'GET', url:u, timeout:8000, returnFullResponse:true, ignoreHttpStatusErrors:true, followRedirect:true, headers:UA }); return { ok:isLive(r.statusCode||0), status:r.statusCode||0, body:String(r.body||'') }; } catch(e){ return { ok:false, status:0, body:'' }; } };

// B: probe https / https+www / http; prefer canonical-tag host variant
const fetchHost = async (host) => {
  for (const u of ['https://'+host, 'https://www.'+host, 'http://'+host]) {
    const r = await get(u);
    if (r.ok && r.body) {
      let root = u.replace(/\/$/,'');
      const cm = r.body.match(/<link[^>]+rel=["']canonical["'][^>]+href=["']([^"']+)["']/i) || r.body.match(/<link[^>]+href=["']([^"']+)["'][^>]+rel=["']canonical["']/i);
      if (cm && /^https?:\/\//i.test(cm[1])) { const ch = hostOf(cm[1]); if (ch && ch === host) { const cu = cm[1].split(/[?#]/)[0].replace(/\/$/,''); if (pathOf(cu)==='' ) root = cu; } }
      return { ok:true, status:r.status, body:r.body, root };
    }
  }
  return { ok:false, status:0, body:'', root:'https://'+host };
};

// A: deterministic contact-signal harvest from an already-fetched body ($0)
const harvest = (body, host) => {
  const out = { emails:[], contact_url:'', socials:{}, site_lang:'' };
  if (!body || body.length < 50) return out;
  const lm = body.match(/<html[^>]*\blang=["']([a-z]{2})(?:[-_][a-z]{2})?["']/i);
  if (lm) out.site_lang = lm[1].toLowerCase();
  else { const om = body.match(/<meta[^>]+property=["']og:locale["'][^>]+content=["']([a-z]{2})/i); if (om) out.site_lang = om[1].toLowerCase(); }
  const bad = /(\.png|\.jpg|\.jpeg|\.gif|\.svg|\.webp|\.ico|example\.|sentry|wixpress|\.wix|godaddy|sedo|your[-.]?email|email@example|domain\.com|test@|@example|@sentry|\.0\b)/i;
  const emails = new Set();
  let m;
  const reMailto = /mailto:([^"'?>\s]+)/gi;
  while ((m = reMailto.exec(body))) { let e=''; try { e = decodeURIComponent(m[1]); } catch(_) { e = m[1]; } e = e.toLowerCase().trim(); if (/^[a-z0-9._%+\-]+@[a-z0-9.\-]+\.[a-z]{2,}$/.test(e) && !bad.test(e)) emails.add(e); }
  const txt = body.replace(/<style[\s\S]*?<\/style>/gi,' ').replace(/<script[\s\S]*?<\/script>/gi,' ');
  const reMail = /[a-z0-9._%+\-]+@[a-z0-9.\-]+\.[a-z]{2,}/gi;
  while ((m = reMail.exec(txt))) { const e = m[0].toLowerCase(); if (!bad.test(e)) emails.add(e); }
  out.emails = Array.from(emails).slice(0,15);
  const soc = { facebook:/https?:\/\/(?:www\.)?facebook\.com\/[^\s"'<>]+/i, instagram:/https?:\/\/(?:www\.)?instagram\.com\/[^\s"'<>]+/i, youtube:/https?:\/\/(?:www\.)?youtube\.com\/[^\s"'<>]+/i, tiktok:/https?:\/\/(?:www\.)?tiktok\.com\/@?[^\s"'<>]+/i, twitter:/https?:\/\/(?:www\.)?(?:twitter|x)\.com\/[^\s"'<>]+/i, linkedin:/https?:\/\/(?:www\.)?linkedin\.com\/[^\s"'<>]+/i };
  for (const k in soc) { const mm = body.match(soc[k]); if (mm) out.socials[k] = mm[0].replace(/[\\"'<>].*$/,''); }
  const kw = /(kontakt|contact|impressum|imprint|about|o-?nas|chi-?siamo|contatti|contacto|contacta|mentions-?legales|nous-?contacter|coordonnees|kapcsolat|kontakti)/i;
  const reA = /<a\b[^>]*href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi; let a;
  while ((a = reA.exec(body))) {
    const href = a[1]; const label = a[2].replace(/<[^>]+>/g,' ');
    if (href && (kw.test(href) || kw.test(label)) && !/^(mailto:|tel:|javascript:|#)/i.test(href)) {
      out.contact_url = /^https?:\/\//i.test(href) ? href : ('https://'+host+'/'+href.replace(/^\.?\//,'').replace(/^\//,''));
      break;
    }
  }
  return out;
};

// Tier-0 belongs heuristic on a fetched body for a given host
const evaluate = (body, host) => {
  const norm = (s)=>String(s||'').toLowerCase().normalize('NFD').replace(/\p{M}/gu,'');
  const grab = (re)=>{ const mm=body.match(re); return mm?mm[1]:''; };
  const title = grab(/<title[^>]*>([\s\S]*?)<\/title>/i);
  const ogSite = grab(/<meta[^>]+property=["']og:site_name["'][^>]+content=["']([^"']*)["']/i);
  const ogTitle = grab(/<meta[^>]+property=["']og:title["'][^>]+content=["']([^"']*)["']/i);
  const h1 = grab(/<h1[^>]*>([\s\S]*?)<\/h1>/i).replace(/<[^>]+>/g,' ');
  const head = norm(title+' '+ogSite+' '+ogTitle+' '+h1);
  const text = norm(body.replace(/<script[\s\S]*?<\/script>/gi,' ').replace(/<style[\s\S]*?<\/style>/gi,' ').replace(/<[^>]+>/g,' ')).replace(/\s+/g,' ').slice(0,8000);
  const tokens = Array.isArray(v.nameTokens) ? v.nameTokens : [];
  const headHit = tokens.some(t => head.includes(t));
  const bodyHit = tokens.some(t => text.includes(t));
  const CC = {'albania':'al','andorra':'ad','armenia':'am','austria':'at','azerbaijan':'az','belarus':'by','belgium':'be','bosnia and herzegovina':'ba','bulgaria':'bg','croatia':'hr','cyprus':'cy','czech republic':'cz','czechia':'cz','denmark':'dk','estonia':'ee','finland':'fi','france':'fr','georgia':'ge','germany':'de','greece':'gr','hungary':'hu','iceland':'is','ireland':'ie','israel':'il','italy':'it','kosovo':'xk','latvia':'lv','liechtenstein':'li','lithuania':'lt','luxembourg':'lu','malta':'mt','moldova':'md','monaco':'mc','montenegro':'me','netherlands':'nl','north macedonia':'mk','norway':'no','poland':'pl','portugal':'pt','romania':'ro','russia':'ru','san marino':'sm','serbia':'rs','slovakia':'sk','slovenia':'si','spain':'es','sweden':'se','switzerland':'ch','turkey':'tr','ukraine':'ua','united kingdom':'uk'};
  const tld = host.split('.').pop();
  const cc = CC[String(club.country||'').toLowerCase().trim()];
  const ccMatch = !!cc && (tld===cc || host.endsWith('.'+cc));
  const geoText = (club.country && text.includes(norm(club.country))) || (club.city && String(club.city).length>=3 && text.includes(norm(club.city)));
  const geo = ccMatch || geoText;
  const dom = host.replace(/[^a-z0-9]/g,'');
  const domHit = tokens.some(t => { const tt=norm(t).replace(/[^a-z0-9]/g,''); return tt.length>=3 && dom.includes(tt); });
  const parked = /(domain (is |may be )?for sale|buy this domain|this domain is for sale|sedoparking|hugedomains|parking-?lander|godaddy)/i.test(body);
  const linkCount = (body.match(/<a\b/gi)||[]).length;
  const directoryish = linkCount>120 && !headHit;
  const VB = /(volley|voleib|voley|pallavolo|siatk|odbojk|roplab|tinklin|воле|voleybol|lentopallo|volleybal|petosf|πετοσφ|βολε)/i;
  const hasVB = VB.test(head) || VB.test(text) || VB.test(dom);
  const MS = /(polisportiv|polideportiv|omnisport|multisport|abteilung|sektion|sezione|seccion|sportgemeinschaft|turnverein|club deportivo)/i;
  const SPORTS = ['football','soccer','fussball','futbol','calcio','basketball','basket','handball','athletic','leichtathletik','schwimm','swimming','natacion','tennis','judo','karate','gymnast','turnen','tischtennis','badminton','hockey','rugby','boxing','atletismo','ciclis','skating','futsal'];
  const sportCount = SPORTS.filter(s => text.includes(s)).length;
  const multi = MS.test(text) || sportCount>=3;
  let verdict='ambiguous', confidence='', club_type='';
  if (parked || directoryish) { verdict='hardfail'; confidence='C'; }
  else if (!hasVB) { verdict='novb'; confidence='C'; }
  else if (headHit && (geo || domHit)) { verdict='strong'; confidence='A'; }
  else { verdict='ambiguous'; }
  if (hasVB) { if (multi) club_type='multisport'; else if (VB.test(head) || VB.test(dom)) club_type='volleyball'; }
  const page = { title: title.replace(/\s+/g,' ').trim().slice(0,200), ogSite: ogSite.slice(0,200), h1: h1.replace(/\s+/g,' ').trim().slice(0,200), excerpt: text.slice(0,1800), headHit, bodyHit, geo, domHit, hasVB, sportCount, club_type_guess: club_type };
  return { verdict, confidence, club_type, hasVB, parked, directoryish, page };
};

let chosen='', source=curSource, status='live', resolved=false, body='', section_url='';
let confidence='', club_type='', verdict='done', page=null, harvested=false, triedCount=0;
let sig = { emails:[], contact_url:'', socials:{}, site_lang:'' };

if (!v.needsResolve) {
  // already live; keep the URL. On recheck, fetch + harvest (A) + re-run belongs (serper only).
  chosen = v.currentUrl; status = 'live';
  if (v.recheck && chosen) {
    const host = hostOf(chosen);
    const r = await get(chosen);
    if (r.ok && r.body) body = r.body;
    if (body && body.length > 200) {
      harvested = true;
      sig = harvest(body, host);
      if (curSource === 'serper') {
        const ev = evaluate(body, host);
        verdict = ev.verdict; if (ev.confidence) confidence = ev.confidence; club_type = ev.club_type; page = ev.page;
      }
    }
  }
  if (status==='live' && (curSource==='official_list' || curSource==='manual') && !confidence) confidence='A';
} else {
  // C+D: ordered candidate pool = LLM pick + query-1 organic + query-2 organic
  let raw = String(($('Pick site').first().json||{}).output || '').trim().replace(/^```(json)?/i,'').replace(/```\s*$/,'').trim();
  let pick=''; try { const o=JSON.parse(raw); pick=String(o.url||'').trim(); } catch(e){ const mm=raw.match(/https?:\/\/[^\s"'}]+/); pick=mm?mm[0]:''; }
  const org1 = (($('Serper Search').first().json||{}).organic) || [];
  let org2 = []; try { org2 = (($('Serper Search 2').first().json||{}).organic) || []; } catch(e){}
  const ordered = [];
  const pushUrl = (u) => { if (!u || !/^https?:\/\//i.test(u)) return; const h = hostOf(u); if (!h || blocked.test(h)) return; ordered.push({ url:u, host:h }); };
  pushUrl(pick);
  org1.forEach(r => pushUrl(r.link));
  org2.forEach(r => pushUrl(r.link));
  const seen = new Set(); const cands = [];
  for (const c of ordered) { if (seen.has(c.host)) continue; seen.add(c.host); cands.push(c); }
  let bestLive = null, bestVB = null;
  for (const c of cands) {
    if (triedCount >= 5) break;
    triedCount++;
    const fh = await fetchHost(c.host);
    if (!fh.ok || !fh.body) continue;
    const ev = evaluate(fh.body, c.host);
    const rec = { c, fh, ev };
    if (!bestLive) bestLive = rec;
    if (ev.hasVB && !ev.parked && !ev.directoryish) { bestVB = rec; break; }
  }
  const winner = bestVB || bestLive;
  if (winner) {
    const host = winner.c.host;
    chosen = winner.fh.root || ('https://'+host);
    body = winner.fh.body;
    source = 'serper'; status = 'live'; resolved = true;
    verdict = winner.ev.verdict; confidence = winner.ev.confidence; club_type = winner.ev.club_type; page = winner.ev.page;
    const p = pathOf(winner.c.url);
    const sectiony = /(volley|voley|pallavolo|siatk|odbojk|abteilung|sektion|sezione|seccion|section|sparte|afdeling|departement)/i.test(p);
    if (p && p !== '/' && p.length > 1 && (club_type === 'multisport' || sectiony)) section_url = winner.c.url.split(/[?#]/)[0];
    harvested = true;
    sig = harvest(body, host);
  } else {
    chosen=''; source='none'; status = v.currentUrl ? 'dead' : 'not_found';
  }
}

const routeAmbiguous = (verdict==='ambiguous');
return [{ json: {
  clubId, chosen, source, status, confidence, club_type, verdict, routeAmbiguous, page,
  section_url, emails: sig.emails, contact_url: sig.contact_url, socials: sig.socials, site_lang: sig.site_lang,
  harvested, triedCount,
  name: v.name, city: v.city, country: v.country
} }];

const PB_URL = ($('Config').first().json.pbUrl || '').replace(/\/+$/, '');
const token = $('PB Auth').first().json.token; const pbH = { Authorization: token };
const r = $('Resolve site').first().json; const clubId = r.clubId;
let conf = r.confidence || '';
let ct = r.club_type || '';
if (r.verdict === 'ambiguous') {
  let belongs = 'unsure', lct = '';
  try {
    const resp = $('Belongs check').first().json;
    const txt = (resp && resp.content && resp.content[0] && resp.content[0].text) || '';
    const o = JSON.parse(String(txt).replace(/```json/gi,'').replace(/```/g,'').trim());
    belongs = String(o.belongs||'unsure').toLowerCase();
    lct = String(o.club_type||'').toLowerCase();
  } catch(e) {}
  conf = (belongs === 'yes') ? 'B' : 'C';
  if (!ct && (lct === 'volleyball' || lct === 'multisport')) ct = lct;
}
const body = { website_url: r.chosen, website_source: r.source, website_status: r.status };
if (conf) body.website_confidence = conf;
if (ct) body.club_type = ct;
// enrichment signals — only when a real body was harvested, and only non-empty (never blank good data)
if (r.harvested) {
  if (Array.isArray(r.emails) && r.emails.length) body.website_emails = r.emails;
  if (r.contact_url) body.contact_url = r.contact_url;
  if (r.socials && Object.keys(r.socials).length) body.socials = r.socials;
  if (r.site_lang) body.site_lang = r.site_lang;
}
if (r.section_url) body.section_url = r.section_url;
await this.helpers.httpRequest({ method:'PATCH', url:PB_URL+'/api/collections/clubs/records/'+clubId, headers:pbH, body, json:true });
const action = !r.chosen ? r.status : ((r.source!=='serper') ? 'live' : 'resolved');
return [{ json: { ok:true, clubId, action, url:r.chosen, confidence: conf||'unknown', club_type: ct||'unknown', emails: (r.emails||[]).length, contact_url: r.contact_url||'', socials: Object.keys(r.socials||{}), site_lang: r.site_lang||'', section_url: r.section_url||'', tried: r.triedCount||0 } }];
